mapper.select:
SELECT a.id, a.alarm_no, a.alarm_type, CASE a.alarm_type WHEN 1 THEN '紧急求助' WHEN 2 THEN '火灾' WHEN 3 THEN '治安' WHEN 4 THEN '校园欺凌' WHEN 5 THEN '食物中毒' WHEN 6 THEN '自然灾害' WHEN 7 THEN '其他' ELSE '未知' END AS alarm_type_name, a.alarm_level, CASE a.alarm_level WHEN 1 THEN '重大' WHEN 2 THEN '较大' WHEN 3 THEN '一般' ELSE '未知' END AS alarm_level_name, a.status, CASE a.status WHEN 1 THEN '待处置' WHEN 2 THEN '处置中' WHEN 3 THEN '已督办' WHEN 4 THEN '已处置' WHEN 5 THEN '已关闭' ELSE '未知' END AS status_name, a.created_at, CASE WHEN a.handled_at IS NOT NULL AND a.first_response_at IS NOT NULL THEN TIMESTAMPDIFF(MINUTE, a.first_response_at, a.handled_at) ELSE NULL END AS handle_duration_minutes FROM alarm_record a WHERE a.deleted = 0 AND a.school_id = #{schoolId}
AND a.id != #{excludeAlarmId}
ORDER BY a.created_at DESC LIMIT #{limit}

SELECT n.id, n.target_name, n.notify_target, n.notify_type, CASE n.notify_type WHEN 1 THEN '短信' WHEN 2 THEN 'APP推送' WHEN 3 THEN '电话' WHEN 4 THEN '邮件' ELSE '未知' END AS notify_type_name, n.sent_at, n.read_at, n.fail_reason FROM notify_record n WHERE n.alarm_id = #{alarmId}
AND n.status = #{status}
ORDER BY n.created_at DESC
